using System.ComponentModel.DataAnnotations;namespace CollegeManagementSystem.Data.Entities;public class Student{    [Key] public int Id { get; set; }    [Required] [MaxLength(50)] public string FirstName { get; set; } = string.Empty;    [Required] [MaxLength(50)] public string LastName { get; set; } = string.Empty;    [Required] public DateTime DateOfBirth { get; set; }    [Required] [MaxLength(10)] public int Phone { get; set; }    [EmailAddress] public string Email { get; set; } = string.Empty;}